"use client"

import { useState, useMemo } from "react";
import Link from "next/link";
import { BottomNav } from "@/components/layout/bottom-nav";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Badge } from "@/components/ui/badge";
import { Card } from "@/components/ui/card";
import { Label } from "@/components/ui/label";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Trophy, Medal, MapPin, Zap, Flame, Crown, Loader2, Clock, Navigation, Map as MapIcon, Star, Ghost, Timer, Flag } from "lucide-react";
import { cn } from "@/lib/utils";
import { useFirestore, useCollection, useMemoFirebase } from "@/firebase";
import { collection, query, where, orderBy, limit } from "firebase/firestore";
import { RenderCarIcon } from "@/components/icons/car-icons";
import { Button } from "@/components/ui/button";

const KOSOVO_CITIES = [
  "Mbarë Kosova", "Prishtinë", "Prizren", "Pejë", "Gjakovë", "Mitrovicë", "Gjilan", "Ferizaj", 
  "Vushtrri", "Podujevë", "Rahovec", "Fushë Kosovë", "Suharekë", "Kaçanik", 
  "Skënderaj", "Lipjan", "Malishevë", "Drenas", "Deçan", "Klinë", "Kamenicë", 
  "Dragash", "Istog", "Viti", "Obiliq", "Leposaviq", "Graçanicë", "Hani i Elezit", 
  "Zveçan", "Shtime", "Novobërdë", "Zubin Potok", "Junik", "Mamushë", 
  "Ranillug", "Partesh", "Kllokot"
];

export default function LeaderboardPage() {
  const [activeTab, setActiveTab] = useState("top-speed");
  const [cityFilter, setCityFilter] = useState("Mbarë Kosova");
  const db = useFirestore();

  const rankingResetDate = useMemo(() => {
    const d = new Date('2024-05-22T00:00:00.000Z'); 
    return d.toISOString();
  }, []);

  const publicRunsQuery = useMemoFirebase(() => {
    if (!db) return null;
    return query(
      collection(db, "public_runs"),
      where("createdAt", ">=", rankingResetDate),
      orderBy("createdAt", "desc"),
      limit(1000)
    );
  }, [db, rankingResetDate]);

  const { data: allRuns, isLoading } = useCollection(publicRunsQuery);

  const filteredRuns = useMemo(() => {
    if (!allRuns) return [];
    if (cityFilter === "Mbarë Kosova") return allRuns;
    return allRuns.filter(run => run.city === cityFilter);
  }, [allRuns, cityFilter]);

  const topSpeedRankings = useMemo(() => {
    const uniqueUsers: Record<string, any> = {};
    filteredRuns.forEach(run => {
      if (!uniqueUsers[run.userId] || run.peakSpeedKmH > uniqueUsers[run.userId].peakSpeedKmH) {
        uniqueUsers[run.userId] = run;
      }
    });
    return Object.values(uniqueUsers).sort((a: any, b: any) => b.peakSpeedKmH - a.peakSpeedKmH);
  }, [filteredRuns]);

  const dragRankings = (type: string) => {
    const uniqueUsers: Record<string, any> = {};
    filteredRuns.filter(r => r.runType === type && r.dragTime).forEach(run => {
      if (!uniqueUsers[run.userId] || run.dragTime < uniqueUsers[run.userId].dragTime) {
        uniqueUsers[run.userId] = run;
      }
    });
    return Object.values(uniqueUsers).sort((a: any, b: any) => a.dragTime - b.dragTime);
  };

  const zeroTo100Rankings = useMemo(() => dragRankings('0-100'), [filteredRuns]);
  const hundredTo200Rankings = useMemo(() => dragRankings('100-200'), [filteredRuns]);
  const quarterMileRankings = useMemo(() => dragRankings('1/4 Mile'), [filteredRuns]);

  return (
    <div className="flex flex-col min-h-screen bg-background text-foreground pb-24 safe-top relative">
      <div className="absolute top-0 left-0 right-0 h-48 bg-gradient-to-b from-accent/10 via-transparent to-transparent pointer-events-none" />
      
      <div className="p-6 pb-2 relative z-10 space-y-4">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-accent/10 rounded-2xl flex items-center justify-center">
            <Trophy className="w-6 h-6 text-accent" />
          </div>
          <div>
            <h1 className="text-xl font-black tracking-tighter uppercase italic leading-none">RANKINGU</h1>
            <p className="text-[10px] text-muted-foreground uppercase font-bold tracking-[0.3em] mt-1">LIVE KOSOVA</p>
          </div>
        </div>

        <div className="space-y-1.5">
          <Label className="text-[9px] font-black uppercase text-muted-foreground px-1 tracking-widest">FILTRO QYTETIN</Label>
          <Select value={cityFilter} onValueChange={setCityFilter}>
            <SelectTrigger className="w-full h-11 glass border-white/10 rounded-xl font-black italic uppercase text-[10px]">
              <SelectValue placeholder="Zgjidh Qytetin" />
            </SelectTrigger>
            <SelectContent className="glass border-white/10 max-h-[260px]">
              {KOSOVO_CITIES.map(c => (
                <SelectItem key={c} value={c} className="font-bold text-[10px] uppercase italic">{c}</SelectItem>
              ))}
            </SelectContent>
          </Select>
        </div>
      </div>

      <Tabs defaultValue="top-speed" onValueChange={setActiveTab} className="w-full px-4 mt-2 relative z-10">
        <TabsList className="flex gap-1 overflow-x-auto no-scrollbar glass border-white/5 h-12 rounded-2xl p-1 shrink-0 mb-6">
          <TabsTrigger value="top-speed" className="rounded-xl flex-1 data-[state=active]:bg-accent data-[state=active]:text-background font-black text-[8px] uppercase italic px-2">SPEED</TabsTrigger>
          <TabsTrigger value="0-100" className="rounded-xl flex-1 data-[state=active]:bg-accent data-[state=active]:text-background font-black text-[8px] uppercase italic px-2">0-100</TabsTrigger>
          <TabsTrigger value="100-200" className="rounded-xl flex-1 data-[state=active]:bg-accent data-[state=active]:text-background font-black text-[8px] uppercase italic px-2">100-200</TabsTrigger>
          <TabsTrigger value="1/4mile" className="rounded-xl flex-1 data-[state=active]:bg-accent data-[state=active]:text-background font-black text-[8px] uppercase italic px-2">1/4 MILE</TabsTrigger>
        </TabsList>

        <div className="space-y-3">
          <TabsContent value="top-speed" className="m-0 space-y-3">
            {topSpeedRankings.map((run: any, index: number) => (
              <LeaderboardCard key={run.id} driver={run} index={index} metric={`${run.peakSpeedKmH} km/h`} runId={run.id} />
            ))}
          </TabsContent>

          <TabsContent value="0-100" className="m-0 space-y-3">
            {zeroTo100Rankings.map((run: any, index: number) => (
              <LeaderboardCard key={run.id} driver={run} index={index} metric={`${run.dragTime?.toFixed(2)}s`} runId={run.id} />
            ))}
          </TabsContent>

          <TabsContent value="100-200" className="m-0 space-y-3">
            {hundredTo200Rankings.map((run: any, index: number) => (
              <LeaderboardCard key={run.id} driver={run} index={index} metric={`${run.dragTime?.toFixed(2)}s`} runId={run.id} />
            ))}
          </TabsContent>

          <TabsContent value="1/4mile" className="m-0 space-y-3">
            {quarterMileRankings.map((run: any, index: number) => (
              <LeaderboardCard key={run.id} driver={run} index={index} metric={`${run.dragTime?.toFixed(2)}s`} runId={run.id} />
            ))}
          </TabsContent>
          
          {!isLoading && filteredRuns.length === 0 && (
            <div className="py-20 text-center opacity-40">
              <p className="text-[10px] font-black uppercase italic tracking-widest">Nuk ka rekorde për këtë qytet.</p>
            </div>
          )}
        </div>
      </Tabs>
      <BottomNav />
    </div>
  );
}

function LeaderboardCard({ driver, index, metric, runId }: { driver: any, index: number, metric: string, runId?: string }) {
  const isTopRank = index === 0;

  return (
    <Card className={cn(
      "glass-card border-white/5 p-4 relative overflow-hidden group transition-all duration-300 rounded-3xl",
      isTopRank && "border-accent/40 bg-accent/[0.04] animate-pulse-green"
    )}>
      <div className="flex items-center gap-3 relative z-10">
        <div className="flex flex-col items-center justify-center min-w-[32px]">
          {index === 0 ? <Trophy className="w-6 h-6 text-accent" /> : 
           index === 1 ? <Medal className="w-6 h-6 text-zinc-400" /> :
           index === 2 ? <Medal className="w-6 h-6 text-orange-600" /> :
           <span className="text-lg font-black text-muted-foreground/30 italic">#{index + 1}</span>}
        </div>
        
        <Link href={`/profile/${driver.userId}`} className="w-12 h-12 rounded-2xl bg-zinc-950 border border-white/5 flex items-center justify-center shadow-lg active:scale-95 shrink-0">
           <RenderCarIcon type={driver.profileIcon} className="w-7 h-7 text-accent" />
        </Link>

        <div className="flex-1 min-w-0">
          <h3 className="font-black text-xs truncate uppercase italic tracking-tight text-white">{driver.username}</h3>
          <div className="flex items-center gap-1 mt-0.5">
            <MapPin className="w-2 h-2 text-accent" />
            <span className="text-[7px] font-black text-muted-foreground uppercase tracking-wider">{driver.city}</span>
          </div>
          <p className="text-[8px] font-bold text-muted-foreground/80 truncate uppercase tracking-wider">{driver.carBrand} {driver.carModel}</p>
        </div>

        <div className="text-right">
          <div className="text-xl font-black italic text-accent leading-none">
            {metric.split(' ')[0]}
          </div>
          <div className="text-[8px] font-black text-muted-foreground uppercase tracking-widest mt-0.5">{metric.split(' ')[1]}</div>
        </div>
      </div>
      
      {runId && (
        <div className="mt-3 pt-3 border-t border-white/5 flex justify-end">
          <Link href={`/race/${runId}`}>
            <Button size="sm" className="h-7 bg-accent/10 hover:bg-accent text-accent hover:text-background font-black italic uppercase text-[8px] rounded-lg px-3">
              BEAT THIS <Zap className="w-2.5 h-2.5 ml-1.5 fill-current" />
            </Button>
          </Link>
        </div>
      )}
    </Card>
  );
}